<template lang="en">
<div>
    <loader :is-visible="isLoading"></loader>
    <section class="main-content">
        <div ref="hellp" id="divMaindealData">
            <div class="border p-3">
                <Form ref="JobPostForm">
                    <dynamic-form lang="en" ref="BarcodeReport" v-if="DataLoaded" :buttons="buttons" :schema="FormSchema" v-on:OnSubmit="onSubmit"></dynamic-form>
                    <div class="row placeholder">
                        <div class="col-md-12 p-0">
                            <ReportViewer v-if="parameter.length > 0" :key="loadKey" :viewerId="'viewer_' + loadKey" :parameter="parameter" :reportPath="reportPath">
                            </ReportViewer>
                        </div>
                    </div>
                </Form>
            </div>
        </div>
    </section>
</div>
</template>

<script>
import '@boldreports/javascript-reporting-controls/Scripts/bold.report-designer.min';
import '@boldreports/javascript-reporting-controls/Scripts/bold.report-viewer.min';
import '@boldreports/javascript-reporting-controls/Scripts/data-visualization/ej.bulletgraph.min';
import '@boldreports/javascript-reporting-controls/Scripts/data-visualization/ej.chart.min';
import DataServices from "../../services/DataService";
import ReportViewer from '../../views/HrReport/ReportViewer.vue';
import moment from 'moment';
export default {
    components: {
        ReportViewer
    },
    data() {
        return {
            isLoading: false,
            reportPath: null,
            parameter: [],
            loadKey: 0,
            DataLoaded: 0,
            FormSchema: [{
                    layoutType: "triple",
                    Data: [{
                            astype: "textField",
                            label: this.$t("INVOICE NUMBER"),
                            name: "INVOICENUMBER",
                            value: "",
                            placeholder: "INVOICE NUMBER"
                        },
                        {
                            astype: "DateRangeField",
                            label: this.$t('Issue Date'),
                            name: "IssueDateFrom",
                            value: "",
                            placeholder: "",
                            config: {
                                format: "MM/DD/YYYY",
                                maxDate: false,
                                onChange: this.setTimerDate,
                                datePickerConfig: {
                                    useCurrent: true,
                                    showClear: true,
                                    showClose: true,
                                    allowInputToggle: false,
                                    minDate: true,
                                    maxDate: true,
                                    widgetPositioning: {
                                        horizontal: 'right',
                                        vertical: 'bottom'
                                    }
                                },
                                secondDatePickerConfig: {
                                    useCurrent: false,
                                    showClear: true,
                                    showClose: true,
                                    allowInputToggle: false,
                                    minDate: true,
                                    maxDate: true,
                                    widgetPositioning: {
                                        horizontal: 'right',
                                        vertical: 'bottom'
                                    }
                                },
                            },
                            validationRules: {
                                "required": false
                            },
                        },
                        {
                            astype: "textField",
                            label: this.$t("Amount Range"),
                            name: "AmountRangeFrom",
                            value: "",
                            placeholder: "From"
                        },
                        {
                            astype: "textField",
                            name: "AmountRangeTo",
                            value: "",
                            placeholder: "To"
                        }
                    ]
                },
                {
                    layoutType: "triple",
                    Data: [{
                            astype: "DateRangeField",
                            label: this.$t('Due Date'),
                            name: "DueDateFrom",
                            value: "",
                            placeholder: "",
                            config: {
                                format: "MM/DD/YYYY",
                                maxDate: false,
                                onChange: this.setTimerDate,
                                datePickerConfig: {
                                    useCurrent: true,
                                    showClear: true,
                                    showClose: true,
                                    allowInputToggle: false,
                                    minDate: true,
                                    maxDate: true,
                                    widgetPositioning: {
                                        horizontal: 'right',
                                        vertical: 'bottom'
                                    }
                                },
                                secondDatePickerConfig: {
                                    useCurrent: false,
                                    showClear: true,
                                    showClose: true,
                                    allowInputToggle: false,
                                    minDate: true,
                                    maxDate: true,
                                    widgetPositioning: {
                                        horizontal: 'right',
                                        vertical: 'bottom'
                                    }
                                },
                            },
                            validationRules: {
                                "required": false
                            },
                        },
                        {
                            astype: "DateRangeField",
                            label: this.$t('Payment Date'),
                            name: "PaymentDateFrom",
                            value: "",
                            placeholder: "",
                            config: {
                                format: "MM/DD/YYYY",
                                maxDate: false,
                                onChange: this.setTimerDate,
                                datePickerConfig: {
                                    useCurrent: true,
                                    showClear: true,
                                    showClose: true,
                                    allowInputToggle: false,
                                    minDate: true,
                                    maxDate: true,
                                    widgetPositioning: {
                                        horizontal: 'right',
                                        vertical: 'bottom'
                                    }
                                },
                                secondDatePickerConfig: {
                                    useCurrent: false,
                                    showClear: true,
                                    showClose: true,
                                    allowInputToggle: false,
                                    minDate: true,
                                    maxDate: true,
                                    widgetPositioning: {
                                        horizontal: 'right',
                                        vertical: 'bottom'
                                    }
                                },
                            },
                            validationRules: {
                                "required": false
                            },
                        },
                        {
                            astype: "SearchableSelectField",
                            label: this.$t("Invoice Status"),
                            name: "InvoiceStatus",
                            value: "",
                            placeholder: this.$t('Select') + " " + this.$t('Invoice Status'),
                            visibility: true,
                            isSearch: false,
                            config: {
                                options: [],
                                isMultiple: false,
                                minSearchLength: 0,
                                actionButtons: {
                                    clear: true
                                },
                                statusFieldConfig: {
                                    fieldName: 'status',
                                    activeValues: ['Active', 'active'],
                                    inactiveValues: ['Inactive', 'inactive'],
                                    activeColor: '#28a745',
                                    inactiveColor: '#dc3545'
                                }
                            },
                            validationRules: {
                                required: false
                            }
                        }
                    ]
                }
            ],
            buttons: [{
                    type: "submit",
                    class: "btn btn-success",
                    text: "<i class='fa fa-search pr-2'></i>Search",
                },
                {
                    type: "button",
                    class: "btn btn-danger",
                    text: "<i class='fa fa-close pr-2'></i>Clear all",
                    onClick: this.ClearAll
                }
            ]
        }
    },
    created: async function () {
        var vm = this;
        vm.userId = vm.GetUserInfo.ID;
        vm.companyId = vm.GetUserInfo.CompanyId;
        vm.UserType = vm.GetUserInfo.UserType;
        vm.DataLoaded = 1;
        await vm.GetStatusList();
    },
    methods: {
        setTimerDate: function (x, y, z) {
            var vm = this;
            if (y.name == "IssuedtFrom") {
                vm.$refs.BarcodeReport.updateProperty("IssuedtTO", "config.minDate", x);
                vm.$refs.BarcodeReport.UpdateKeyValue();
            }
            if (y.name == "DuedtFrom") {
                vm.$refs.BarcodeReport.updateProperty("DuedtTO", "config.minDate", x);
                vm.$refs.BarcodeReport.UpdateKeyValue();
            }
            if (y.name == "PaymentdtFrom") {
                vm.$refs.BarcodeReport.updateProperty("PaymentdtTO", "config.minDate", x);
                vm.$refs.BarcodeReport.UpdateKeyValue();
            }
        },
        ClearAll: function () {
            var vm = this;
            (vm.FormSchema)[0].Data[0].value = '';
            (vm.FormSchema)[0].Data[1].value = '';
            (vm.FormSchema)[0].Data[1].secondValue = '';
            (vm.FormSchema)[0].Data[2].value = '';
            (vm.FormSchema)[0].Data[3].value = '';
            (vm.FormSchema)[1].Data[0].value = '';
            (vm.FormSchema)[1].Data[0].secondValue = '';
            (vm.FormSchema)[1].Data[1].value = '';
            (vm.FormSchema)[1].Data[1].secondValue = '';
            (vm.FormSchema)[1].Data[2].value = '';
            vm.reportPath = '';
            vm.parameter = [];
            vm.loadKey = 0;
            vm.$refs.BarcodeReport.validateForm.reset();
        },
        formatDate(value) {
            if (!value) return null;
            const m = moment(value);
            return m.isValid() ? m.format('MM-DD-YYYY') : null;
        },
        async onSubmit(e) {
            var vm = this;
            vm.isLoading = true;
            vm.loadKey = Date.now();
            vm.reportPath = '';
            vm.parameter = [];

            vm.IssueDateFrom = vm.$refs.BarcodeReport.getPropertyValue("IssueDateFrom", "value");
            vm.IssueDateTo = vm.$refs.BarcodeReport.getPropertyValue("IssueDateFrom", "secondValue");
            vm.DueDateFrom = vm.$refs.BarcodeReport.getPropertyValue("DueDateFrom", "value");
            vm.DueDateTo = vm.$refs.BarcodeReport.getPropertyValue("DueDateFrom", "secondValue");
            vm.PaymentDateFrom = vm.$refs.BarcodeReport.getPropertyValue("PaymentDateFrom", "value");
            vm.PaymentDateTo = vm.$refs.BarcodeReport.getPropertyValue("PaymentDateFrom", "secondValue");

            let myObj = {
                reportName: "invoicedetailreport",
                invoiceNumber: e.INVOICENUMBER,
                billIssueDateFrom: vm.formatDate(vm.IssueDateFrom),
                billIssueDateTo: vm.formatDate(vm.IssueDateTo),
                AmountFrom: e.AmountRangeFrom,
                AmountTo: e.AmountRangeTo,
                billDueDateFrom: vm.formatDate(vm.DueDateFrom),
                billDueDateTo: vm.formatDate(vm.DueDateTo),
                billpaymentDateFrom: vm.formatDate(vm.PaymentDateFrom),
                billpaymentTo: vm.formatDate(vm.PaymentDateTo),
                StatusIds: e.InvoiceStatus,
            }
            var postString = JSON.stringify(myObj);
            DataServices.ReportMain(postString).then(function (response) {
                vm.reportPath = response.data.reportpath;
                vm.parameter = response.data.parameters;
                vm.isLoading = false;
            }).catch(function (error) {
                console.error("Error loading report:", error);
                vm.isLoading = false;
            });
        },
        GetStatusList: async function () {
            var vm = this;
            var url = `langCode=en&statusType=ClientBilling&hasglobal=false`
            await DataServices.GetStatusList(url).then((response) => {
                let SelectedStatusList = [];
                var StatusList = response.data;
                if (StatusList != null) {
                    StatusList.forEach(item => {
                        let obj = {
                            description: null,
                            displayValue: item.STATUS,
                            groupText: null,
                            groupValue: null,
                            metaData: null,
                            text: item.STATUS,
                            value: item.STATUS_ID
                        };
                        SelectedStatusList.push(obj);
                    });
                    vm.$refs.BarcodeReport.updateProperty("InvoiceStatus", "config.options", SelectedStatusList);
                    vm.$refs.BarcodeReport.UpdateKeyValue();
                }
            });
        }
    }
};
</script>

<style>
/* ================================
   AMOUNT RANGE – FINAL FIX
   ================================ */

/* Make the row containing AmountRangeFrom the anchor */
#AmountRangeFrom.col-lg-4 {
    position: relative;
    width: 66.666666% !important;
    /* span 2 columns */
    max-width: 66.666666% !important;
}

/* Fix From input size */
#AmountRangeFrom input {
    width: 150px !important;
    max-width: 150px !important;
}

/* Place To inside the same visual column */
#AmountRangeTo.col-lg-4 {
    position: absolute;
    top: 24px;
    /* aligns with input field */
    right: 3px;
    /* From width + gap */
    width: auto !important;
    max-width: none !important;
}

/* Fix To input size */
#AmountRangeTo input {
    width: 150px !important;
    max-width: 150px !important;
}

/* Remove empty label space for To */
#AmountRangeTo label {
    display: none;
}
</style>
