<template lang="en">
<div>
    <loader :is-visible="isLoading"></loader>
    <section class="main-content">
        <div ref="hellp" id="divMaindealData">
            <div class="border p-3">
                <Form ref="JobPostForm">
                    <dynamic-form lang="en" ref="BarcodeReport" v-if="DataLoaded" :buttons="buttons" :schema="FormSchema" v-on:OnSubmit="onSubmit" :mandatorytext='MandatoryString'></dynamic-form>
                    <div class="row placeholder">
                        <div class="col-md-12 p-0">
                            <ReportViewer v-if="parameter.length > 0" :key="loadKey" :viewerId="'viewer_' + loadKey" :parameter="parameter" :reportPath="reportPath">
                            </ReportViewer>
                        </div>
                    </div>
                </Form>
            </div>
        </div>
    </section>
</div>
</template>
<script>
import '@boldreports/javascript-reporting-controls/Scripts/bold.report-designer.min';
import '@boldreports/javascript-reporting-controls/Scripts/bold.report-viewer.min';
import '@boldreports/javascript-reporting-controls/Scripts/data-visualization/ej.bulletgraph.min';
import '@boldreports/javascript-reporting-controls/Scripts/data-visualization/ej.chart.min';
import DataServices from "../../services/DataService";
import ReportViewer from '../../views/HrReport/ReportViewer.vue';
import moment from 'moment';
export default {
    components: {
        ReportViewer
    },
    data() {
        return {
            MandatoryString: 'Fields marked with an asterisk (*) are mandatory.',
            isLoading: false,
            loadKey: 0,
            reportPath: null,
            parameter: [],
            DataLoaded: 0,
            FormSchema: [{
                    layoutType: "triple",
                    Data: [{
                            astype: "SearchableSelectField",
                            label: this.$t("ClientName"),
                            name: "ClientName",
                            value: "",
                            placeholder: this.$t('Select'),
                            visibility: true,
                            isSearch: false,
                            config: {
                                options: [],
                                isMultiple: false,
                                minSearchLength: 0,
                                groupFields: ['groupText'],
                                actionButtons: {
                                    clear: true
                                },
                                onChange: this.GetUtilityByClient
                            },
                            validationRules: {
                                required: true
                            }
                        },
                        {
                            astype: "SearchableSelectField",
                            label: this.$t("UtilityName"),
                            name: "UtilityName",
                            value: "",
                            placeholder: this.$t('Select'),
                            visibility: true,
                            isSearch: false,
                            config: {
                                options: [],
                                isMultiple: true,
                                minSearchLength: 0,
                                groupFields: [],
                                actionButtons: {
                                    selectAll: true,
                                    clear: true
                                }
                            },
                            validationRules: {
                                required: false
                            }
                        },
                        {
                            astype: "SelectField",
                            label: this.$t("Status"),
                            name: "Status",
                            value: "",
                            placeholder: this.$t('Select Status'),
                            mode: "tag",
                            config: {
                                options: [{
                                    name: 'Processed',
                                    value: 'Processed'
                                }, {
                                    name: 'Unprocessed',
                                    value: 'Unprocessed'
                                }]
                            },
                            validationRules: {
                                "required": true
                            }
                        }
                    ]
                },
                {
                    layoutType: "triple",
                    Data: [
                        {
                            astype: "DateRangeField",
                            label: this.$t('Work_Date'),
                            name: "WorkDateFrom",
                            value: "",
                            placeholder: "",
                            config: {
                                format: "MM/DD/YYYY",
                                maxDate: false,
                                onChange: this.setTimerDate,
                                datePickerConfig: {
                                    useCurrent: true,
                                    showClear: true,
                                    showClose: true,
                                    allowInputToggle: false,
                                    minDate: true,
                                    maxDate: true,
                                    widgetPositioning: {
                                        horizontal: 'right',
                                        vertical: 'bottom'
                                    }
                                },
                                secondDatePickerConfig: {
                                    useCurrent: false,
                                    showClear: true,
                                    showClose: true,
                                    allowInputToggle: false,
                                    minDate: true,
                                    maxDate: true,
                                    widgetPositioning: {
                                        horizontal: 'right',
                                        vertical: 'bottom'
                                    }
                                },
                            },
                            validationRules: {
                                "required": false
                            },
                        },
                        {
                            astype: "DateRangeField",
                            label: this.$t('Import Date'),
                            name: "ImportDateFrom",
                            value: "",
                            placeholder: "",
                            config: {
                                format: "MM/DD/YYYY",
                                maxDate: false,
                                onChange: this.setTimerDate,
                                datePickerConfig: {
                                    useCurrent: true,
                                    showClear: true,
                                    showClose: true,
                                    allowInputToggle: false,
                                    minDate: true,
                                    maxDate: true,
                                    widgetPositioning: {
                                        horizontal: 'right',
                                        vertical: 'bottom'
                                    }
                                },
                                secondDatePickerConfig: {
                                    useCurrent: false,
                                    showClear: true,
                                    showClose: true,
                                    allowInputToggle: false,
                                    minDate: true,
                                    maxDate: true,
                                    widgetPositioning: {
                                        horizontal: 'right',
                                        vertical: 'bottom'
                                    }
                                },
                            },
                            validationRules: {
                                "required": false
                            },
                        },
                        {
                            astype: "SelectField",
                            label: this.$t("State"),
                            name: "State",
                            value: "",
                            placeholder: this.$t('Select State'),
                            mode: "tag",
                            config: {
                                options: []
                            }
                        },
                        {
                            astype: "TextField",
                            label: this.$t("TicketNumber"),
                            name: "TicketNumber",
                            value: "",
                            placeholder: "Ticket Number",
                        }
                    ]
                }
            ],
            buttons: [{
                    type: "submit",
                    class: "btn btn-success",
                    text: "<i class='fa fa-search pr-2'></i>Search",
                },
                {
                    type: "button",
                    class: "btn btn-danger",
                    text: "<i class='fa fa-close pr-2'></i>Clear all",
                    onClick: this.ClearAll
                }
            ]
        }
    },
    created: async function () {
        var vm = this;
        vm.userId = vm.GetUserInfo.ID;
        vm.companyId = vm.GetUserInfo.CompanyId;
        vm.UserType = vm.GetUserInfo.UserType;
        vm.DataLoaded = 1;
        await vm.GetClient();
        await vm.GetDDLStateList();
    },
    methods: {
        setTimerDate: function (x, y, z) {
            var vm = this;
            if (y.name == "WorkDateFrom") {
                vm.$refs.BarcodeReport.updateProperty("WorkDateFrom", "config.secondDatePickerConfig.minDate", x);
                vm.$refs.BarcodeReport.UpdateKeyValue();
            }
            if (y.name == "ImportDateFrom") {
                vm.$refs.BarcodeReport.updateProperty("ImportDateFrom", "config.secondDatePickerConfig.minDate", x);
                vm.$refs.BarcodeReport.UpdateKeyValue();
            }
        },
        formatDate(value) {
            if (!value) return null;
            const m = moment(value);
            return m.isValid() ? m.format('MM-DD-YYYY') : null;
        },
        onSubmit(e) {
            var vm = this;
            vm.isLoading = true;
            vm.loadKey = Date.now();
            vm.reportPath = '';
            vm.parameter = [];
            vm.WorkDateFrom = vm.$refs.BarcodeReport.getPropertyValue("WorkDateFrom", "value");
            vm.WorkDateTo = vm.$refs.BarcodeReport.getPropertyValue("WorkDateFrom", "secondValue");
            vm.ImportDateFrom = vm.$refs.BarcodeReport.getPropertyValue("ImportDateFrom", "value");
            vm.ImportDateTo = vm.$refs.BarcodeReport.getPropertyValue("ImportDateFrom", "secondValue");
            let myObj = {
                reportName: "processedunprocessedreport",
                ClientIds: e.ClientName,
                UtilityIds: e.UtilityName.length > 0 ? e.UtilityName.map(item => item.value).join(",") : '',
                Status: e.Status,
                dateFrom: vm.formatDate(vm.WorkDateFrom),
                dateTo: vm.formatDate(vm.WorkDateTo),
                importDateFrom: vm.formatDate(vm.ImportDateFrom),
                importdateTo: vm.formatDate(vm.ImportDateTo),
                State: e.State,
                TicketNumber: e.TicketNumber
            }
            var postString = JSON.stringify(myObj);
            DataServices.ReportMain(postString).then(function (response) {
                vm.reportPath = response.data.reportpath;
                vm.parameter = response.data.parameters;
                vm.isLoading = false;
            }).catch(function (error) {
                console.error("Error loading report:", error);
                vm.isLoading = false;
            });
        },
        ClearAll: function () {
            var vm = this;
            (vm.FormSchema)[0].Data[0].value = '';
            (vm.FormSchema)[0].Data[1].value = '';
            (vm.FormSchema)[0].Data[1].config.options = [];
            (vm.FormSchema)[0].Data[2].value = '';
            (vm.FormSchema)[1].Data[0].value = '';
            (vm.FormSchema)[1].Data[0].secondValue = '';
            (vm.FormSchema)[1].Data[1].value = '';
            (vm.FormSchema)[1].Data[1].secondValue = '';
            (vm.FormSchema)[1].Data[2].value = '';
            (vm.FormSchema)[1].Data[3].value = '';
            vm.reportPath = '';
            vm.parameter = [];
            vm.loadKey = 0;
            vm.$refs.BarcodeReport.validateForm.reset();
        },
        GetClient: async function () {
            var vm = this;
            vm.isLoading = true;
            var params = 'pageNumber=&pageSize=&Reqfrom="CUSTOM"&search=null&userId=null';
            try {
                let response = await DataServices.GetClient(params);
                if (response.data && response.data.length > 0) {
                    let clientOptions = response.data.map(item => ({
                        text: item.CHILD_NAME,
                        displayValue: item.CHILD_NAME,
                        value: item.CHILD_USER_ID,
                        description: null,
                        groupText: null,
                        groupValue: null,
                        metaData: null
                    }));
                    vm.$refs.BarcodeReport.updateProperty("ClientName", "config.options", clientOptions);
                    vm.$refs.BarcodeReport.UpdateKeyValue();
                } else {
                    vm.$refs.BarcodeReport.updateProperty("ClientName", "config.options", []);
                    vm.$refs.BarcodeReport.UpdateKeyValue();
                }
            } catch (error) {
                console.error("Error fetching client list:", error);
                vm.$refs.BarcodeReport.updateProperty("ClientName", "config.options", []);
                vm.$refs.BarcodeReport.UpdateKeyValue();
            } finally {
                vm.isLoading = false;
            }
        },
        GetUtilityByClient: async function (value, selected) {
            var vm = this;
            // Reset Utility dropdown
            vm.$refs.BarcodeReport.updateProperty("UtilityName", "config.options", []);
            vm.$refs.BarcodeReport.updateProperty("UtilityName", "value", '');
            vm.$refs.BarcodeReport.UpdateKeyValue();
            if (!selected) return;
            // ✅ selected IS the clientId
            var ClientIds = selected;
            var url = `clientId=${ClientIds}&configid=0&Reqfrom=&clientIds=`;
            vm.isLoading = true;
            try {
                let response = await DataServices.GetUtilityByClient(url);
                if (response.data && response.data.length > 0) {
                    let utilityOptions = response.data.map(item => ({
                        text: item.UTILITY_NAME,
                        displayValue: item.UTILITY_NAME,
                        value: item.UTILITY_ID,
                        description: null,
                        groupText: null,
                        groupValue: null,
                        metaData: null
                    }));
                    vm.$refs.BarcodeReport.updateProperty("UtilityName", "config.options", utilityOptions);
                    vm.$refs.BarcodeReport.UpdateKeyValue();
                }
            } catch (error) {
                console.error("Error loading utility list:", error);
                vm.$refs.BarcodeReport.updateProperty("UtilityName", "config.options", []);
                vm.$refs.BarcodeReport.UpdateKeyValue();
            } finally {
                vm.isLoading = false;
            }
        },
        GetDDLStateList: async function () {
            var vm = this;
            var params = `CountryId=223&InclueCandaState=true`;
            try {
                let response = await DataServices.GetDDLStateList(params);
                if (response.data && response.data.length > 0) {
                    let stateOptions = response.data.map(item => ({
                        name: item.STATE_NAME + '(' + item.ISO_CODE_3 + ')',
                        value: item.ISO_CODE_3
                    }));
                    vm.$refs.BarcodeReport.updateProperty("State", "config.options", stateOptions);
                    vm.$refs.BarcodeReport.UpdateKeyValue();
                } else {
                    vm.$refs.BarcodeReport.updateProperty("State", "config.options", []);
                    vm.$refs.BarcodeReport.UpdateKeyValue();
                }
            } catch (error) {
                console.error("Error fetching state list:", error);
                vm.$refs.BarcodeReport.updateProperty("State", "config.options", []);
                vm.$refs.BarcodeReport.UpdateKeyValue();
            }
        }
    }
}
</script>