<template lang="en">
<div>
    <loader :is-visible="isLoading"></loader>
    <section class="main-content">
        <div ref="hellp" id="divMaindealData">
            <div class="border p-3">
                <Form ref="JobPostForm">
                    <dynamic-form lang="en" ref="BarcodeReport" v-if="DataLoaded" :buttons="buttons" :schema="FormSchema" v-on:OnSubmit="onSubmit"></dynamic-form>
                    <div class="row placeholder">
                        <div class="col-md-12 p-0">
                            <ReportViewer v-if="parameter.length > 0" :key="loadKey" :viewerId="'viewer_' + loadKey" :parameter="parameter" :reportPath="reportPath">
                            </ReportViewer>
                        </div>
                    </div>
                </Form>
            </div>
        </div>
    </section>
</div>
</template>
<script>
import '@boldreports/javascript-reporting-controls/Scripts/bold.report-designer.min';
import '@boldreports/javascript-reporting-controls/Scripts/bold.report-viewer.min';
import '@boldreports/javascript-reporting-controls/Scripts/data-visualization/ej.bulletgraph.min';
import '@boldreports/javascript-reporting-controls/Scripts/data-visualization/ej.chart.min';
import DataServices from "../../services/DataService";
import ReportViewer from '../../views/HrReport/ReportViewer.vue';
import moment from 'moment';
export default {
    components: {
        ReportViewer
    },
    data() {
        return {
            isLoading: false,
            DataLoaded: 0,
            loadKey: 0,
            reportPath: null,
            parameter: [],
            FormSchema: [{
                    layoutType: "triple",
                    Data: [{
                            astype: "SearchableSelectField",
                            label: this.$t("ClientName"),
                            name: "Clientname",
                            value: "",
                            placeholder: this.$t('Select'),
                            visibility: true,
                            isSearch: false,
                            config: {
                                options: [],
                                isMultiple: true,
                                minSearchLength: 0,
                                groupFields: [],
                                actionButtons: {
                                    selectAll: true,
                                    clear: true
                                },
                                onChange: this.onContractChange
                            },
                            validationRules: {
                                required: false
                            }
                        },
                        {
                            astype: "SearchableSelectField",
                            label: this.$t("UtilityName"),
                            name: "UtilityName",
                            value: "",
                            placeholder: this.$t('Select'),
                            visibility: true,
                            isSearch: false,
                            config: {
                                options: [],
                                isMultiple: true,
                                minSearchLength: 0,
                                groupFields: [],
                                actionButtons: {
                                    selectAll: true,
                                    clear: true
                                },
                                onChange: this.onUtilityChange
                            },
                            validationRules: {
                                required: false
                            }
                        },
                        {
                            astype: "SearchableSelectField",
                            label: this.$t("Invoice grouping"),
                            name: "Invoicegrouping",
                            value: "",
                            placeholder: this.$t('Select'),
                            visibility: true,
                            isSearch: false,
                            config: {
                                options: [],
                                isMultiple: true,
                                minSearchLength: 0,
                                groupFields: [],
                                actionButtons: {
                                    selectAll: true,
                                    clear: true
                                }
                            },
                            validationRules: {
                                required: false
                            }
                        }
                    ]
                },
                {
                    layoutType: "triple",
                    Data: [
                        {
                            astype: "DateRangeField",
                            label: this.$t('Date From'),
                            name: "DateFrom",
                            value: "",
                            placeholder: "",
                            config: {
                                format: "MM/DD/YYYY",
                                maxDate: false,
                                onChange: this.setTimerDate,
                                datePickerConfig: {
                                    useCurrent: true,
                                    showClear: true,
                                    showClose: true,
                                    allowInputToggle: false,
                                    minDate: true,
                                    maxDate: true,
                                    widgetPositioning: {
                                        horizontal: 'right',
                                        vertical: 'bottom'
                                    }
                                },
                                secondDatePickerConfig: {
                                    useCurrent: false,
                                    showClear: true,
                                    showClose: true,
                                    allowInputToggle: false,
                                    minDate: true,
                                    maxDate: true,
                                    widgetPositioning: {
                                        horizontal: 'right',
                                        vertical: 'bottom'
                                    }
                                },
                            },
                            validationRules: {
                                "required": false
                            },
                        },
                        {
                            astype: "SearchableSelectField",
                            label: this.$t("Notes Status"),
                            name: "NoteStatus",
                            value: "",
                            placeholder: this.$t('Select'),
                            visibility: true,
                            isSearch: false,
                            config: {
                                options: [],
                                isMultiple: false,
                                minSearchLength: 0,
                                groupFields: ['groupText'],
                                actionButtons: {
                                    clear: true
                                }
                            },
                            validationRules: {
                                required: false
                            }
                        },
                        {
                            astype: "SearchableSelectField",
                            label: this.$t("State"),
                            name: "State",
                            value: "",
                            placeholder: this.$t('Select'),
                            visibility: true,
                            isSearch: false,
                            config: {
                                options: [],
                                isMultiple: false,
                                minSearchLength: 0,
                                groupFields: ['groupText'],
                                actionButtons: {
                                    clear: true
                                }
                            },
                            validationRules: {
                                required: false
                            }
                        },
                        {
                            astype: "SearchableSelectField",
                            label: this.$t("Note Type"),
                            name: "NoteType",
                            value: "",
                            placeholder: this.$t('Select'),
                            visibility: true,
                            isSearch: false,
                            config: {
                                options: [],
                                isMultiple: true,
                                minSearchLength: 0,
                                groupFields: [],
                                actionButtons: {
                                    selectAll: true,
                                    clear: true
                                }
                            },
                            validationRules: {
                                required: false
                            }
                        },
                        {
                            astype: "toggleField",
                            label: this.$t('Show Current Value'),
                            name: "ShowCurrentValue",
                            value: false,
                            placeholder: "",
                            validationRules: ""
                        }
                    ]
                }
            ],
            buttons: [{
                    type: "submit",
                    class: "btn btn-success",
                    text: "<i class='fa fa-search pr-2'></i>Search",
                },
                {
                    type: "button",
                    class: "btn btn-danger",
                    text: "<i class='fa fa-close pr-2'></i>Clear all",
                    onClick: this.ClearAll
                }
            ]
        }
    },
    created: async function () {
        var vm = this;
        vm.userId = vm.GetUserInfo.ID;
        vm.companyId = vm.GetUserInfo.CompanyId;
        vm.UserType = vm.GetUserInfo.UserType;
        vm.DataLoaded = 1;
        await vm.GetClient();
        await vm.GetStatusList();
        await vm.GetDDLStateList();
        await vm.$nextTick(); // Ensure refs are ready
        // Hardcode NoteType options after refs are ready
        let noteTypeOptions = [
            {
                text: 'Utility',
                displayValue: 'Utility',
                value: 'Utility',
                description: null,
                groupText: null,
                groupValue: null,
                metaData: null
            },
            {
                text: 'Invoice Grouping',
                displayValue: 'Invoice Grouping',
                value: 'InvoiceGrouping',
                description: null,
                groupText: null,
                groupValue: null,
                metaData: null
            }
        ];
        vm.$refs.BarcodeReport.updateProperty("NoteType", "config.options", noteTypeOptions);
        vm.$refs.BarcodeReport.UpdateKeyValue();
    },
    methods: {
        setTimerDate: function (x, y, z) {
            var vm = this;
            if (y.name == "DateFrom") {
                vm.$refs.BarcodeReport.updateProperty("DateFrom", "config.secondDatePickerConfig.minDate", x);
                vm.$refs.BarcodeReport.UpdateKeyValue();
            }
        },
        formatDate(value) {
            if (!value) return null;
            const m = moment(value);
            return m.isValid() ? m.format('MM-DD-YYYY') : null;
        },
        async onSubmit(e) {
            var vm = this;
            vm.isLoading = true;
            vm.loadKey = Date.now();
            vm.reportPath = '';
            vm.parameter = [];
            vm.DateFrom = vm.$refs.BarcodeReport.getPropertyValue("DateFrom", "value");
            vm.DateTo = vm.$refs.BarcodeReport.getPropertyValue("DateFrom", "secondValue");
           
            let myObj = {
                reportName: "notesreport",
                ClientIds: e.Clientname && e.Clientname.length > 0 ? e.Clientname.join(",") : '',
                UtilityIds: e.UtilityName && e.UtilityName.length > 0 ? e.UtilityName.join(",") : '',
                DivisionId: e.Invoicegrouping && e.Invoicegrouping.length > 0 ? e.Invoicegrouping.join(",") : '',
                dateFrom: vm.formatDate(vm.DateFrom),
                dateTo: vm.formatDate(vm.DateTo),
                StatusIds: e.NoteStatus ? e.NoteStatus.value : '',
                State: e.State ? e.State.value : '',
                NoteType: e.NoteType && e.NoteType.length > 0 ? e.NoteType.join(",") : '',
                CurrentVal: e.ShowCurrentValue ? 1 : 0
            }
            var postString = JSON.stringify(myObj);
            try {
                let response = await DataServices.ReportMain(postString);
                vm.reportPath = response.data.reportpath;
                vm.parameter = response.data.parameters;
            } catch (error) {
                console.error("Error loading report:", error);
            } finally {
                vm.isLoading = false;
            }
        },
        ClearAll: function () {
            var vm = this;
            (vm.FormSchema)[0].Data[0].value = '';
            (vm.FormSchema)[0].Data[1].value = '';
            (vm.FormSchema)[0].Data[1].config.options = [];
            (vm.FormSchema)[0].Data[2].value = '';
            (vm.FormSchema)[0].Data[2].config.options = [];
            (vm.FormSchema)[1].Data[0].value = '';
            (vm.FormSchema)[1].Data[0].secondValue = '';
            (vm.FormSchema)[1].Data[1].value = '';
            (vm.FormSchema)[1].Data[2].value = '';
            (vm.FormSchema)[1].Data[3].value = '';
            (vm.FormSchema)[1].Data[4].value = false;
            vm.reportPath = '';
            vm.parameter = [];
            vm.loadKey = 0;
            vm.$refs.BarcodeReport.validateForm.reset();
        },
        async GetClient() {
            var vm = this;
            vm.isLoading = true;
            var params = 'pageNumber=&pageSize=&Reqfrom="CUSTOMREPORT"&search=null&userId=null';
            try {
                let response = await DataServices.GetClient(params);
                if (response.data && response.data.length > 0) {
                    let clientOptions = response.data.map(item => ({
                        text: item.CHILD_NAME,
                        displayValue: item.CHILD_NAME,
                        value: item.CHILD_USER_ID,
                        description: null,
                        groupText: null,
                        groupValue: null,
                        metaData: null
                    }));
                    vm.$refs.BarcodeReport.updateProperty("Clientname", "config.options", clientOptions);
                    vm.$refs.BarcodeReport.UpdateKeyValue();
                } else {
                    vm.$refs.BarcodeReport.updateProperty("Clientname", "config.options", []);
                    vm.$refs.BarcodeReport.UpdateKeyValue();
                }
            } catch (error) {
                console.error("Error fetching clients:", error);
                vm.$refs.BarcodeReport.updateProperty("Clientname", "config.options", []);
                vm.$refs.BarcodeReport.UpdateKeyValue();
            } finally {
                vm.isLoading = false;
            }
        },
        async onContractChange() {
            var vm = this;
            const currentValue = vm.$refs.BarcodeReport.getPropertyValue("Clientname", "value");
            const clientIds = currentValue && currentValue.length > 0 ? currentValue.join(",") : '';

            debugger;
            // Reset dependents
            vm.$refs.BarcodeReport.updateProperty("UtilityName", "config.options", []);
            vm.$refs.BarcodeReport.updateProperty("UtilityName", "value", []);
            vm.$refs.BarcodeReport.updateProperty("Invoicegrouping", "config.options", []);
            vm.$refs.BarcodeReport.updateProperty("Invoicegrouping", "value", []);
            vm.$refs.BarcodeReport.UpdateKeyValue();
            if (!clientIds) return;
            vm.isLoading = true;
            try {
                const params = {
                    clientId: '',
                    configid: 0,
                    Reqfrom: "BILLED_UNBILLED_REPORT",
                    clientIds: clientIds
                };
                const queryString = new URLSearchParams(params).toString();
                let response = await DataServices.GetUtilityByClient(queryString);
                if (response.data && response.data.length > 0) {
                    let utilityOptions = response.data.map(item => ({
                        text: item.UTILITY_NAME,
                        displayValue: item.UTILITY_NAME,
                        value: item.UTILITY_ID,
                        description: null,
                        groupText: null,
                        groupValue: null,
                        metaData: null
                    }));
                    vm.$refs.BarcodeReport.updateProperty("UtilityName", "config.options", utilityOptions);
                    vm.$refs.BarcodeReport.UpdateKeyValue();
                }
                // Populate initial Invoice Grouping (with no utility filter)
                await vm.GetInvoiceGrouping(clientIds, '');
            } catch (error) {
                console.error("Error loading utilities:", error);
                vm.$refs.BarcodeReport.updateProperty("UtilityName", "config.options", []);
                vm.$refs.BarcodeReport.UpdateKeyValue();
            } finally {
                vm.isLoading = false;
            }
        },
        async onUtilityChange() {
            var vm = this;
            const currentUtilityValue = vm.$refs.BarcodeReport.getPropertyValue("UtilityName", "value");
            const utilityIds = currentUtilityValue && currentUtilityValue.length > 0 ? currentUtilityValue.join(",") : '';
            // Get current client selection
            const currentClientValue = vm.$refs.BarcodeReport.getPropertyValue("Clientname", "value");
            const clientIds = currentClientValue && currentClientValue.length > 0 ? currentClientValue.join(",") : '';
            // Reset grouping
            vm.$refs.BarcodeReport.updateProperty("Invoicegrouping", "config.options", []);
            vm.$refs.BarcodeReport.updateProperty("Invoicegrouping", "value", []);
            vm.$refs.BarcodeReport.UpdateKeyValue();
            if (!clientIds) return;
            await vm.GetInvoiceGrouping(clientIds, utilityIds);
        },
        async GetInvoiceGrouping(clientIds, utilityIds) {
            var vm = this;
            if (!clientIds) {
                vm.$refs.BarcodeReport.updateProperty("Invoicegrouping", "config.options", []);
                vm.$refs.BarcodeReport.UpdateKeyValue();
                return;
            }
            vm.isLoading = true;
            try {
                var url = `ClientId=${clientIds}&UtilityIds=${utilityIds}`;
                let response = await DataServices.GetInvoiceGrouping(url);
                if (response.data && response.data.length > 0) {
                    let groupingOptions = response.data.map(item => ({
                        text: item.NOTE,
                        displayValue: item.NOTE,
                        value: item.ID,
                        description: null,
                        groupText: null,
                        groupValue: null,
                        metaData: null
                    }));
                    vm.$refs.BarcodeReport.updateProperty("Invoicegrouping", "config.options", groupingOptions);
                    vm.$refs.BarcodeReport.UpdateKeyValue();
                } else {
                    vm.$refs.BarcodeReport.updateProperty("Invoicegrouping", "config.options", []);
                    vm.$refs.BarcodeReport.UpdateKeyValue();
                }
            } catch (error) {
                console.error("Error fetching invoice groupings:", error);
                vm.$refs.BarcodeReport.updateProperty("Invoicegrouping", "config.options", []);
                vm.$refs.BarcodeReport.UpdateKeyValue();
            } finally {
                vm.isLoading = false;
            }
        },
        async GetStatusList() {
            var vm = this;
            var url = `langCode=en&statusType=Department&hasglobal=true`;
            try {
                let response = await DataServices.GetStatusList(url);
                if (response.data && response.data.length > 0) {
                    let statusOptions = response.data.map(item => ({
                        text: item.STATUS,
                        displayValue: item.STATUS,
                        value: item.STATUS_ID,
                        description: null,
                        groupText: null,
                        groupValue: null,
                        metaData: null
                    }));
                    vm.$refs.BarcodeReport.updateProperty("NoteStatus", "config.options", statusOptions);
                    vm.$refs.BarcodeReport.UpdateKeyValue();
                } else {
                    vm.$refs.BarcodeReport.updateProperty("NoteStatus", "config.options", []);
                    vm.$refs.BarcodeReport.UpdateKeyValue();
                }
            } catch (error) {
                console.error("Error fetching status list:", error);
                vm.$refs.BarcodeReport.updateProperty("NoteStatus", "config.options", []);
                vm.$refs.BarcodeReport.UpdateKeyValue();
            }
        },
        async GetDDLStateList() {
            var vm = this;
            var params = `CountryId=223&InclueCandaState=true`;
            try {
                let response = await DataServices.GetDDLStateList(params);
                if (response.data && response.data.length > 0) {
                    let stateOptions = response.data.map(item => ({
                        text: item.STATE_NAME + '(' + item.ISO_CODE_3 + ')',
                        displayValue: item.STATE_NAME + '(' + item.ISO_CODE_3 + ')',
                        value: item.ISO_CODE_3,
                        description: null,
                        groupText: null,
                        groupValue: null,
                        metaData: null
                    }));
                    vm.$refs.BarcodeReport.updateProperty("State", "config.options", stateOptions);
                    vm.$refs.BarcodeReport.UpdateKeyValue();
                } else {
                    vm.$refs.BarcodeReport.updateProperty("State", "config.options", []);
                    vm.$refs.BarcodeReport.UpdateKeyValue();
                }
            } catch (error) {
                console.error("Error fetching state list:", error);
                vm.$refs.BarcodeReport.updateProperty("State", "config.options", []);
                vm.$refs.BarcodeReport.UpdateKeyValue();
            }
        }
    }
}
</script>