<template lang="en">
<div>
    <loader :is-visible="isLoading"></loader>
    <section class="main-content">
        <div ref="hellp" id="divMaindealData">
            <div class="border p-3">
                <Form ref="JobPostForm">
                    <dynamic-form lang="en" ref="AccountDetailReport" v-if="DataLoaded" :buttons="buttons" :schema="FormSchema" v-on:OnSubmit="onSubmit" :mandatorytext='MandatoryString'></dynamic-form>
                    <div class="row placeholder">
                        <div class="col-md-12 p-0">
                            <div 
                                v-for="(item, index) in reports" 
                                :key="loadKey + '_' + index" 
                                class="report-wrapper" 
                                style="margin-bottom: 20px; border: 1px solid #ddd; border-radius: 4px; overflow: hidden;">
                                <ReportViewer
                                    :viewerId="'viewer_' + loadKey + '_' + index"
                                    :parameter="item.parameter"
                                    :reportPath="item.reportPath">
                                </ReportViewer>
                            </div>
                        </div>
                    </div>
                </Form>
            </div>
        </div>
    </section>
</div>
</template>
<script>
import '@boldreports/javascript-reporting-controls/Scripts/bold.report-designer.min';
import '@boldreports/javascript-reporting-controls/Scripts/bold.report-viewer.min';
import '@boldreports/javascript-reporting-controls/Scripts/data-visualization/ej.bulletgraph.min';
import '@boldreports/javascript-reporting-controls/Scripts/data-visualization/ej.chart.min';
import DataServices from "../../services/DataService";
import {
    locateBillingService
} from "../../services/locateBillingService";
import ReportViewer from '../../views/HrReport/ReportViewer.vue';
export default {
    components: {
        ReportViewer
    },
    data() {
        return {
            MandatoryString: 'Fields marked with an asterisk (*) are mandatory.',
            reports: [],
            isLoading: false,
            reportPath: null,
            parameter: [],
            ClientData: [],
            LocationId: 0,
            loadKey: 0,  // Track unique load for keys/IDs
            FormSchema: [{
                layoutType: "triple",
                Data: [
                    {
                        astype: "SearchableSelectField",
                        label: this.$t('CONTRACTNAME'),
                        name: "ContractName",
                        value: "",
                        placeholder:this.$t('SelectClient'),
                        visibility: true,
                        isSearch: false,
                        config: {
                            options: [],
                        actionButtons: {
                            selectAll: true,
                            active: true,
                            inactive: true,
                            clear: true
                        },
                            isMultiple: false,
                            groupFields: ['groupText'],
                            minSearchLength: 0,
                            statusFieldConfig: {
                                fieldName: 'status',
                                activeValues: ['Active', 'active'],
                                inactiveValues: ['Inactive', 'inactive'],
                                activeColor: '#28a745',
                                inactiveColor: '#dc3545'
                            },
                            onChange: this.onSelectionChange
                        },
                        validationRules: {
                            "required": true
                        },
                    },
                    {
                        astype: "SearchableSelectField",
                        label: this.$t('UtilityName'),
                        name: "UtilityName",
                        value: "",
                        placeholder: "Select Utility Name",
                        visibility: true,
                        isSearch: false,
                        config: {
                            options: [],
                            actionButtons: {
                            selectAll: true,
                            clear: true},
                            groupFields: [],
                            isMultiple: true,
                            minSearchLength: 0,
                            statusFieldConfig: {
                                fieldName: 'status',
                                activeValues: ['Active', 'active'],
                                inactiveValues: ['Inactive', 'inactive'],
                                activeColor: '#28a745',
                                inactiveColor: '#dc3545'
                            },
                        },
                        validationRules: {
                            "required": false
                        },
                    },
                ]
            },
            ],
            buttons: [{
                type: "submit",
                class: "btn btn-success",
                text: "<i class='fa fa-search pr-2'></i>Search",
            },
            {
                type: "button",
                class: "btn btn-danger",
                text: "<i class='fa fa-close pr-2'></i>Clear all",
                onClick: this.ClearAll
            },
            ],
            DataLoaded: 0,
        };
    },
    created: async function () {
        var vm = this;
        vm.userId = vm.GetUserInfo.ID;
        vm.companyId = vm.GetUserInfo.CompanyId;
        vm.UserType = vm.GetUserInfo.UserType;
        vm.DataLoaded = 1;
        await vm.fetchclientlist();
    },
    methods: {
        ClearAll: function () {
            var vm = this;
            (vm.FormSchema)[0].Data[0].value = '';
            (vm.FormSchema)[0].Data[1].value = '';
            vm.FormSchema[0].Data[1].config.options = [];
            vm.reportPath = '';
            vm.parameter = [];
            vm.reports = [];
            vm.loadKey = 0;  // Reset loadKey on clear
            vm.$refs.AccountDetailReport.validateForm.reset();
        },
           fetchclientlist: function () {
            var vm = this;
            vm.isLoading = true;
            var url = `reqFrom=CUSTOMREPORT`;
            locateBillingService.getClientList(url).then(response => {
                vm.isLoading = false;
                vm.ClientData = response.data.items;
                vm.$refs.AccountDetailReport.updateProperty("ContractName", "config.options", vm.ClientData);
                vm.$refs.AccountDetailReport.UpdateKeyValue();

            }).catch(error => {
                vm.isLoading = false;
                vm.ClientData = []; 
                vm.$refs.AccountDetailReport.updateProperty("ContractName", "config.options", vm.ClientData);
                vm.$refs.AccountDetailReport.UpdateKeyValue();
                console.error('Error fetching client list:', error);
            }).finally(() => {
                vm.isLoading = false;
            });
        },
        convertApiTreeToFlatList(tree) {
            let flat = [];
            function walkParent(node) {
                flat.push({
                    CHILD_USER_ID: node.parenT_ID,
                    CHILD_NAME: node.parenT_NAME,
                    PARENT_ID: null
                });
                if (node.children && node.children.length > 0) {
                    node.children.forEach(child => {
                        flat.push({
                            CHILD_USER_ID: child.chilD_USER_ID,
                            CHILD_NAME: child.chilD_NAME,
                            PARENT_ID: node.parenT_ID
                        });
                    });
                }
            }
            tree.forEach(root => walkParent(root));
            return flat;
        },
        onSelectionChange(value, x) {
            var vm = this;
            vm.isLoading = true;
            vm.selectedClientId = x;
            var url = `clientId=${x}&configId=&reqFrom=&clientIds=`;
            locateBillingService.getUtilityList(url).then(response => {
                let SelectedUtilityList = [];
                var UtilityList = response.data;
                if (UtilityList != null) {
                    UtilityList.forEach(item => {
                        let obj = {
                            description: null,
                            displayValue: item.UTILITY_NAME,
                            groupText: null,
                            groupValue: null,
                            metaData: null,
                            text: item.UTILITY_NAME,
                            value: item.UTILITY_ID
                        };
                        SelectedUtilityList.push(obj);
                    });
                    vm.$refs.AccountDetailReport.updateProperty("UtilityName", "config.options", SelectedUtilityList);
                    vm.$refs.AccountDetailReport.UpdateKeyValue();
                }
            }).catch(error => {
                vm.isLoading = false;
                vm.UtilityList = [];
                vm.$refs.AccountDetailReport.updateProperty("UtilityName", "config.options", []);
                vm.$refs.AccountDetailReport.updateProperty("UtilityName", "value", '');
            }).finally(() => {
                vm.isLoading = false;
            });
        },
       
        async onSubmit(e) {
            this.isLoading = true;
            this.loadKey = Date.now();  // Generate unique key for this load
            this.reports = [];  // Clear old reports (components will unmount)
            let commonParams = {
                ClientIds: e.ContractName,
                UtilityIds: e.UtilityName && Object.keys(e.UtilityName).length > 0? Object.values(e.UtilityName).join(",") : ''
            };
            try {
                // Wait for unmount to complete before pushing new reports
                await this.$nextTick();
                
                // Report 1
                let response1 = await DataServices.ReportMain(JSON.stringify({
                    reportName: "detailaccount",
                    ...commonParams
                }));
                this.reports.push({
                    reportPath: response1.data.reportpath,
                    parameter: response1.data.parameters
                    // Removed unused viewerId
                });
                // Report 2
                let response2 = await DataServices.ReportMain(JSON.stringify({
                    reportName: "detailaccountdivisionrate",
                    ...commonParams
                }));
                this.reports.push({
                    reportPath: response2.data.reportpath,
                    parameter: response2.data.parameters
                    // Removed unused viewerId
                });

                // Report 3
                let response3 = await DataServices.ReportMain(JSON.stringify({
                    reportName: "detailaccountsbareport",
                    ...commonParams
                }));
                this.reports.push({
                    reportPath: response3.data.reportpath,
                    parameter: response3.data.parameters
                    // Removed unused viewerId
                });
            } catch (error) {
                console.error("Error while loading reports:", error);
            } finally {
                this.isLoading = false;
            }
        }
    }
};
</script>

<style scoped>
.report-wrapper {
  margin-bottom: 20px;
}
.report-wrapper:last-child {
  margin-bottom: 0;
}
</style>