<template lang="en">
<div>
    <loader :is-visible="isLoading"></loader>
    <section class="main-content">
        <div ref="hellp" id="divMaindealData">
            <div class="border p-3">
                <Form ref="JobPostForm">
                    <dynamic-form lang="en" ref="BarcodeReport" v-if="DataLoaded" :buttons="buttons" :schema="FormSchema" v-on:OnSubmit="onSubmit" :mandatorytext='MandatoryString'></dynamic-form>
                    <div class="row placeholder">
                        <div class="col-md-12 p-0">
                            <ReportViewer v-if="parameter.length > 0" :key="loadKey" :viewerId="'viewer_' + loadKey" :parameter="parameter" :reportPath="reportPath">
                            </ReportViewer>
                        </div>
                    </div>
                </Form>
            </div>
        </div>
    </section>
</div>
</template>

<script>
import '@boldreports/javascript-reporting-controls/Scripts/bold.report-designer.min';
import '@boldreports/javascript-reporting-controls/Scripts/bold.report-viewer.min';
import '@boldreports/javascript-reporting-controls/Scripts/data-visualization/ej.bulletgraph.min';
import '@boldreports/javascript-reporting-controls/Scripts/data-visualization/ej.chart.min';
import DataServices from "../../services/DataService";
import ReportViewer from '../../views/HrReport/ReportViewer.vue';
import moment from 'moment';
import { locateBillingService } from "../../services/locateBillingService";
export default {
    components: {
        ReportViewer
    },
    data() {
        return {
            MandatoryString: 'Fields marked with an asterisk (*) are mandatory.',
            isLoading: false,
            reportPath: null,
            parameter: [],
            clientIds: '',
            LocationId: 0,
            loadKey: 0,
            FormSchema: [{
                    layoutType: "triple",
                    Data: [{
                            astype: "SearchableSelectField",
                            label: this.$t('CONTRACTNAME'),
                            name: "ContractName",
                            value: "",
                            placeholder: this.$t('SelectClient'),
                            visibility: true,
                            isSearch: true,
                            config: {
                                options: [],
                                actionButtons: {
                                    selectAll: true,
                                    active: true,
                                    inactive: true,
                                    clear: true
                                },
                                isMultiple: true,
                                groupFields: ['groupText'],
                                minSearchLength: 0,
                                statusFieldConfig: {
                                    fieldName: 'status',
                                    activeValues: ['Active', 'active'],
                                    inactiveValues: ['Inactive', 'inactive'],
                                    activeColor: '#28a745',
                                    inactiveColor: '#dc3545'
                                },
                                onChange: this.onSelectionChange
                            },
                            validationRules: {
                                "required": false
                            },
                        },
                        {
                            astype: "SearchableSelectField",
                            label: this.$t('UtilityName'),
                            name: "UtilityName",
                            value: "",
                            placeholder: "Select Utility Name",
                            visibility: true,
                            isSearch: false,
                            config: {
                                options: [],
                                actionButtons: {
                                    selectAll: true,
                                    clear: true
                                },
                                groupFields: [],
                                isMultiple: true,
                                minSearchLength: 0,
                                statusFieldConfig: {
                                    fieldName: 'status',
                                    activeValues: ['Active', 'active'],
                                    inactiveValues: ['Inactive', 'inactive'],
                                    activeColor: '#28a745',
                                    inactiveColor: '#dc3545'
                                },
                                onChange: this.LoadDivisionList
                            },
                            validationRules: {
                                "required": false
                            },
                        },
                        {
                            astype: "SearchableSelectField",
                            label: this.$t('Division'),
                            name: "Invoicegrouping",
                            value: "",
                            placeholder: "Select Utility Name",
                            visibility: true,
                            isSearch: false,
                            config: {
                                options: [],
                                actionButtons: {
                                    selectAll: true,
                                    clear: true
                                },
                                groupFields: [],
                                isMultiple: true,
                                minSearchLength: 0,
                                statusFieldConfig: {
                                    fieldName: 'status',
                                    activeValues: ['Active', 'active'],
                                    inactiveValues: ['Inactive', 'inactive'],
                                    activeColor: '#28a745',
                                    inactiveColor: '#dc3545'
                                },
                            },
                            validationRules: {
                                "required": false
                            }
                        }
                    ]
                },
                {
                    layoutType: "triple",
                    Data: [{
                            astype: "SelectField",
                            label: this.$t("Status"),
                            name: "Status",
                            value: "",
                            placeholder: this.$t('Select') + " " + this.$t('Status'),
                            mode: "tag",
                            config: {
                                options: [{
                                    name: 'Billed Records',
                                    value: "1"
                                }, {
                                    name: 'Unbilled Records',
                                    value: "2"
                                }]
                            },
                            validationRules: {
                                "required": true
                            }
                        },
                        {
                            astype: "DateRangeField",
                            label: this.$t('Work_Date'),
                            name: "WorkDateFrom",
                            value: "",
                            placeholder: "",
                            config: {
                                format: "MM/DD/YYYY",
                                maxDate: false,
                                onChange: this.setTimerDate,
                                datePickerConfig: {
                                    useCurrent: true,
                                    showClear: true,
                                    showClose: true,
                                    allowInputToggle: false,
                                    minDate: true,
                                    maxDate: true,
                                    widgetPositioning: {
                                        horizontal: 'right',
                                        vertical: 'bottom'
                                    }
                                },
                                secondDatePickerConfig: {
                                    useCurrent: false,
                                    showClear: true,
                                    showClose: true,
                                    allowInputToggle: false,
                                    minDate: true,
                                    maxDate: true,
                                    widgetPositioning: {
                                        horizontal: 'right',
                                        vertical: 'bottom'
                                    }
                                },
                            },
                            validationRules: {
                                "required": false
                            }
                        },
                        {
                            astype: "SearchableSelectField",
                            label: this.$t("State"),
                            name: "State",
                            value: "",
                            placeholder: this.$t('Select') + " " + this.$t('State'),
                            visibility: true,
                            isSearch: true,
                            config: {
                                options: [],
                                isMultiple: false, 
                                minSearchLength: 0,
                                actionButtons: {
                                    clear: true
                                },
                                statusFieldConfig: {
                                    fieldName: 'status',
                                    activeValues: ['Active', 'active'],
                                    inactiveValues: ['Inactive', 'inactive'],
                                    activeColor: '#28a745',
                                    inactiveColor: '#dc3545'
                                }
                            },
                            validationRules: {
                                required: true
                            }
                        }
                    ]
                },
                {
                    layoutType: "triple",
                    Data: [{
                            astype: "SelectField",
                            label: this.$t("Frequency"),
                            name: "Frequency",
                            value: "",
                            placeholder: this.$t('Select') + " " + this.$t('Status'),
                            mode: "tag",
                            config: {
                                options: [{
                                    name: 'Annually',
                                    value: "annual"
                                }, {
                                    name: 'Bi-Weekly',
                                    value: "biweek"
                                }, {
                                    name: 'Custom Date',
                                    value: "custom"
                                }, {
                                    name: 'Daily',
                                    value: "daily"
                                }, {
                                    name: 'Half yearly',
                                    value: "halfyear"
                                }, {
                                    name: 'Monthly',
                                    value: "month"
                                }, {
                                    name: 'Quarterly',
                                    value: "quarterly"
                                }, {
                                    name: 'Weekly',
                                    value: "week"
                                }]
                            },
                            validationRules: {
                                "required": false
                            }
                        },
                        {
                            astype: "DateRangeField",
                            label: this.$t('Proccess Date'),
                            name: "ProccessDateFrom",
                            value: "",
                            placeholder: "",
                            config: {
                                format: "MM/DD/YYYY",
                                maxDate: false,
                                onChange: this.setTimerDate,
                                datePickerConfig: {
                                    useCurrent: true,
                                    showClear: true,
                                    showClose: true,
                                    allowInputToggle: false,
                                    minDate: true,
                                    maxDate: true,
                                    widgetPositioning: {
                                        horizontal: 'right',
                                        vertical: 'bottom'
                                    }
                                },
                                secondDatePickerConfig: {
                                    useCurrent: false,
                                    showClear: true,
                                    showClose: true,
                                    allowInputToggle: false,
                                    minDate: true,
                                    maxDate: true,
                                    widgetPositioning: {
                                        horizontal: 'right',
                                        vertical: 'bottom'
                                    }
                                },
                            },
                            validationRules: {
                                "required": false
                            },
                        },
                        {
                            astype: "SearchableSelectField",
                            label: this.$t("Work Code"),
                            name: "Workcode",
                            value: "",
                            placeholder: this.$t('Select') + " " + this.$t('State'),
                            visibility: true,
                            isSearch: true,
                            config: {
                                options: [],
                                isMultiple: false, // ✅ SINGLE selection
                                minSearchLength: 0,
                                actionButtons: {
                                    clear: true
                                },
                                statusFieldConfig: {
                                    fieldName: 'status',
                                    activeValues: ['Active', 'active'],
                                    inactiveValues: ['Inactive', 'inactive'],
                                    activeColor: '#28a745',
                                    inactiveColor: '#dc3545'
                                }
                            },
                            validationRules: {
                                required: true
                            }
                        }
                    ]
                }
            ],
            buttons: [{
                    type: "submit",
                    class: "btn btn-success",
                    text: "<i class='fa fa-search pr-2'></i>Search",
                },
                {
                    type: "button",
                    class: "btn btn-danger",
                    text: "<i class='fa fa-close pr-2'></i>Clear all",
                    onClick: this.ClearAll
                }
            ],
            DataLoaded: 0,
        };
    },
    created: async function () {
        var vm = this;
        vm.userId = vm.GetUserInfo.ID;
        vm.companyId = vm.GetUserInfo.CompanyId;
        vm.UserType = vm.GetUserInfo.UserType;
        vm.DataLoaded = 1;
        await vm.fetchclientlist();
        await vm.GetDDLStateList();
        await vm.GetWorkCodeInfo();
    },
    methods: {
        formatDate(value) {
            if (!value) return null;
            const m = moment(value);
            return m.isValid() ? m.format('MM-DD-YYYY') : null;
        },
        setTimerDate: function (x, y, z) {
            var vm = this;
            if (y.name == "Fromdate") {
                vm.$refs.BarcodeReport.updateProperty("ToDate", "config.minDate", x);
                vm.$refs.BarcodeReport.UpdateKeyValue();
            }
            if (y.name == "ProccessFromdate") {
                vm.$refs.BarcodeReport.updateProperty("ProccessToDate", "config.minDate", x);
                vm.$refs.BarcodeReport.UpdateKeyValue();
            }
        },
        async onSubmit(e) {
            var vm = this;
            vm.isLoading = true;
            vm.loadKey = Date.now();
            vm.reportPath = '';
            vm.parameter = [];
            vm.WorkDateFrom = vm.$refs.BarcodeReport.getPropertyValue("WorkDateFrom", "value");
            vm.WorkDateTo = vm.$refs.BarcodeReport.getPropertyValue("WorkDateFrom", "secondValue");
            vm.ProccessDateFrom = vm.$refs.BarcodeReport.getPropertyValue("ProccessDateFrom", "value");
            vm.ProccessDateTo = vm.$refs.BarcodeReport.getPropertyValue("ProccessDateFrom", "secondValue");

            let myObj = {
                reportName: "billedunbilledsummaryreport",
                ClientIds: e.ContractName.length > 0 ? e.ContractName.join(",") : '',
                fDate: vm.formatDate(vm.WorkDateFrom),
                tDate: vm.formatDate(vm.WorkDateTo),
                ProccessFromDate: vm.formatDate(vm.ProccessDateFrom),
                ProccessToDate: vm.formatDate(vm.ProccessDateTo),
                Invoicegrouping: e.Invoicegrouping.length > 0 ? e.Invoicegrouping.join(",") : '',
                State: e.State,
                Status: e.Status,
                Frequency: e.Frequency,
                UtilityIds: e.UtilityName.length > 0 ? e.UtilityName.join(",") : '',
                WorkCodeId: e.Workcode,
            }
            var postString = JSON.stringify(myObj);
            DataServices.ReportMain(postString).then(function (response) {
                vm.reportPath = response.data.reportpath;
                vm.parameter = response.data.parameters;
                vm.isLoading = false;
            }).catch(function (error) {
                console.error("Error loading report:", error);
                vm.isLoading = false;
            });
        },
        ClearAll: function () {
            var vm = this;
            vm.FormSchema[0].Data[1].config.options = [];
            (vm.FormSchema)[0].Data[0].value = '';
            (vm.FormSchema)[0].Data[1].value = '';
            (vm.FormSchema)[1].Data[1].secondValue = '';
            (vm.FormSchema)[0].Data[2].value = '';
            (vm.FormSchema)[1].Data[0].value = '';
            (vm.FormSchema)[1].Data[1].value = '';
            (vm.FormSchema)[1].Data[2].value = '';
            (vm.FormSchema)[2].Data[0].value = '';
            (vm.FormSchema)[2].Data[1].value = '';
            (vm.FormSchema)[2].Data[1].secondValue = '';
            (vm.FormSchema)[2].Data[2].value = '';
            vm.reportPath = '';
            vm.parameter = [];
            vm.loadKey = 0;
            vm.currentReportParams = null;
            vm.$refs.BarcodeReport.validateForm.reset();
        },
        fetchclientlist: function () {
            var vm = this;
            vm.isLoading = true;
            var url = `reqFrom=CUSTOMREPORT`;
            locateBillingService.getClientList(url).then(response => {
                vm.isLoading = false;
                vm.ClientData = response.data.items;
                vm.$refs.BarcodeReport.updateProperty("ContractName", "config.options", vm.ClientData);
                vm.$refs.BarcodeReport.UpdateKeyValue();

            }).catch(error => {
                vm.isLoading = false;
                vm.ClientData = [];
                vm.$refs.BarcodeReport.updateProperty("ContractName", "config.options", vm.ClientData);
                vm.$refs.BarcodeReport.UpdateKeyValue();
                console.error('Error fetching client list:', error);
            }).finally(() => {
                vm.isLoading = false;
            });
        },
        onSelectionChange(value, x) {
            var vm = this;
            vm.isLoading = true;
            if (x.length > 0) {
                vm.selectedClientId = x;
                vm.clientId = x;
            } else {
                vm.selectedClientId = null;
                vm.clientId = null;
            }
            var url = `clientId=${vm.selectedClientId}&configId=&reqFrom=&clientIds=`;
            locateBillingService.getUtilityList(url).then(response => {
                let SelectedUtilityList = [];
                var UtilityList = response.data;
                if (UtilityList != null) {
                    UtilityList.forEach(item => {
                        let obj = {
                            description: null,
                            displayValue: item.UTILITY_NAME,
                            groupText: null,
                            groupValue: null,
                            metaData: null,
                            text: item.UTILITY_NAME,
                            value: item.UTILITY_ID
                        };
                        SelectedUtilityList.push(obj);
                    });
                    vm.$refs.BarcodeReport.updateProperty("UtilityName", "config.options", SelectedUtilityList);
                    vm.$refs.BarcodeReport.updateProperty("Invoicegrouping", "config.options", []);
                    vm.$refs.BarcodeReport.updateProperty("Invoicegrouping", "value", '');
                    vm.$refs.BarcodeReport.UpdateKeyValue();
                }
            }).catch(error => {
                vm.isLoading = false;
                vm.UtilityList = [];
                vm.$refs.BarcodeReport.updateProperty("UtilityName", "config.options", []);
                vm.$refs.BarcodeReport.updateProperty("Invoicegrouping", "config.options", []);
                vm.$refs.BarcodeReport.updateProperty("Invoicegrouping", "value", '');
                vm.$refs.BarcodeReport.updateProperty("UtilityName", "value", '');
            }).finally(() => {
                vm.isLoading = false;
            });
        },
        LoadDivisionList(value, x) {
            var vm = this;
            vm.isLoading = true;
            var url = `ClientId=${vm.clientId}&UtilityIds=`;
            DataServices.GetInvoiceGrouping(url).then(response => {
                vm.isLoading = false;
                let SelectedDivisionList = [];
                var DivisionList = response.data;
                if (DivisionList != null) {
                    DivisionList.forEach(item => {
                        let obj = {
                            description: null,
                            displayValue: item.NOTE,
                            groupText: null,
                            groupValue: null,
                            metaData: null,
                            text: item.NOTE,
                            value: item.ID
                        };
                        SelectedDivisionList.push(obj);
                    });
                }
                vm.$refs.BarcodeReport.updateProperty("Invoicegrouping", "value", "");
                vm.$refs.BarcodeReport.updateProperty("Invoicegrouping", "config.options", SelectedDivisionList);
                vm.$refs.BarcodeReport.UpdateKeyValue();
            }).catch(error => {
                vm.isLoading = false;
                vm.$refs.BarcodeReport.updateProperty("Invoicegrouping", "config.options", []);
                vm.$refs.BarcodeReport.updateProperty("Invoicegrouping", "value", "");
                vm.$refs.BarcodeReport.UpdateKeyValue();
                console.error('Error loading divisions:', error);
            });
        },
        GetInvoiceGrouping: async function (x, y, z) {
            var vm = this;
            var url = `ClientId=${vm.clientIds}&UtilityIds=`;
            await DataServices.GetInvoiceGrouping(url).then((response) => {
                if (response.data.length > 0) {
                    var UtilityData = response.data;
                    UtilityData.forEach(element => {
                        var Obj = {
                            name: element.NOTE,
                            value: element.ID
                        }
                        vm.FormSchema[0].Data[2].config.options.push(Obj);
                    });
                    vm.$refs.BarcodeReport.UpdateKeyValue();
                }
            });
        },
        GetDDLStateList: async function () {
            var vm = this;
            vm.isLoading = true;
            var params = `CountryId=223&InclueCandaState=true`;
            DataServices.GetDDLStateList(params).then((response) => {
                let SelectedStateList = [];
                vm.isLoading = true;
                if (response.data.length > 0) {
                    var StateData = response.data;
                    StateData.forEach(item => {
                        let obj = {
                            description: null,
                            displayValue: item.STATE_NAME + '(' + item.ISO_CODE_3 + ')',
                            groupText: null,
                            groupValue: null,
                            metaData: null,
                            text: item.STATE_NAME + '(' + item.ISO_CODE_3 + ')',
                            value: item.ISO_CODE_3
                        };
                        SelectedStateList.push(obj);
                    });
                    vm.$refs.BarcodeReport.updateProperty("State", "config.options", SelectedStateList);
                    vm.$refs.BarcodeReport.UpdateKeyValue();
                }
            });
        },
        GetWorkCodeInfo: async function () {
            var vm = this;
            vm.isLoading = true;
            DataServices.GetWorkCodeInfo().then((response) => {
                let SelectedStateList = [];
                vm.isLoading = true;
                if (response.data.length > 0) {
                    var WorkCodeData = response.data;
                    WorkCodeData.forEach(item => {
                        let obj = {
                            description: null,
                            displayValue: item.work_code,
                            groupText: null,
                            groupValue: null,
                            metaData: null,
                            text: item.work_code,
                            value: item.work_code_id
                        };
                        SelectedStateList.push(obj);
                    });
                    vm.$refs.BarcodeReport.updateProperty("Workcode", "config.options", SelectedStateList);
                    vm.$refs.BarcodeReport.UpdateKeyValue();
                }
            });
        }
    }
};
</script>