<template lang="en">
<div>
    <loader :is-visible="isLoading"></loader>
    <section class="main-content">
        <div ref="hellp" id="divMaindealData">
            <div class="border p-3">
                <Form ref="JobPostForm">
                    <dynamic-form lang="en" ref="BarcodeReport" v-if="DataLoaded" :buttons="buttons" :schema="FormSchema" v-on:OnSubmit="onSubmit"></dynamic-form>
                    <div class="row placeholder">
                        <div class="col-md-12 p-0">
                            <ReportViewer v-if="parameter.length > 0" :key="loadKey" :viewerId="'viewer_' + loadKey" :parameter="parameter" :reportPath="reportPath">
                            </ReportViewer>
                        </div>
                    </div>
                </Form>
            </div>
        </div>
    </section>
</div>
</template>

<script>
import '@boldreports/javascript-reporting-controls/Scripts/bold.report-designer.min';
import '@boldreports/javascript-reporting-controls/Scripts/bold.report-viewer.min';
import '@boldreports/javascript-reporting-controls/Scripts/data-visualization/ej.bulletgraph.min';
import '@boldreports/javascript-reporting-controls/Scripts/data-visualization/ej.chart.min';
import DataServices from "../../services/DataService";
import ReportViewer from '../../views/HrReport/ReportViewer.vue';
export default {
    components: {
        ReportViewer
    },
    data() {
        return {
            isLoading: false,
            reportPath: null,
            parameter: [],
            CategoryData: [], 
            DataLoaded: 0,
            loadKey: 0, 
            FormSchema: [{
                layoutType: "triple",
                Data: [{
                        astype: "textField",
                        label: this.$t("Service Name"),
                        name: "ServiceName",
                        value: "",
                        placeholder: this.$t('Select') + " " + this.$t('Service Name'),
                        mode: "tag",
                        config: {
                            options: [],
                        }
                    },
                    {
                        astype: "SearchableSelectField",
                        label: this.$t("Service Category"),
                        name: "ServiceCategory",
                        value: "",
                        placeholder: this.$t('Select') + " " + this.$t('Service Category'),
                        visibility: true,
                        isSearch: false,
                        config: {
                            options: [],
                            isMultiple: false, 
                            minSearchLength: 0,
                            actionButtons: {
                                clear: true
                            },
                            statusFieldConfig: {
                                fieldName: 'status',
                                activeValues: ['Active', 'active'],
                                inactiveValues: ['Inactive', 'inactive'],
                                activeColor: '#28a745',
                                inactiveColor: '#dc3545'
                            }
                        },
                        validationRules: {
                            required: true
                        }
                    }
                ]
            }],
            buttons: [{
                    type: "submit",
                    class: "btn btn-success",
                    text: "<i class='fa fa-search pr-2'></i>Search",
                },
                {
                    type: "button",
                    class: "btn btn-danger",
                    text: "<i class='fa fa-close pr-2'></i>Clear all",
                    onClick: this.ClearAll
                },
            ]
        };
    },
    created: async function () {
        var vm = this;
        vm.userId = vm.GetUserInfo.ID;
        vm.companyId = vm.GetUserInfo.CompanyId;
        vm.UserType = vm.GetUserInfo.UserType;
        vm.DataLoaded = 1;
        await vm.GetBillingServices();
        await vm.GetBillingServiceCategory();
    },
    methods: {
        async onSubmit(e) {
            var vm = this;
            vm.isLoading = true;
            vm.loadKey = Date.now(); 
            vm.reportPath = '';
            vm.parameter = [];

            let myObj = {
                reportName: "billingservicelistreport",
                ServiceName: e.ServiceName,
                CategoryIds: e.ServiceCategory
            }
            var postString = JSON.stringify(myObj);
            DataServices.ReportMain(postString).then(function (response) {
                vm.reportPath = response.data.reportpath;
                vm.parameter = response.data.parameters;
                vm.isLoading = false;
            }).catch(function (error) {
                console.error("Error loading report:", error);
                vm.isLoading = false;
            });
        },
        ClearAll: function () {
            var vm = this;
            (vm.FormSchema)[0].Data[0].value = '';
            (vm.FormSchema)[0].Data[1].value = '';
            vm.reportPath = '';
            vm.parameter = [];
            vm.loadKey = 0; 
            vm.$refs.BarcodeReport.validateForm.reset();
        },
        GetBillingServices: async function () {
            var vm = this;
            await DataServices.GetBillingServices().then((response) => {
                if (response.data.length > 0) {
                    var ServiceData = response.data;
                    ServiceData.forEach(element => {
                        var Obj = {
                            name: element.SERVICE_NAME,
                            value: element.SERVICE_ID
                        }
                        vm.FormSchema[0].Data[0].config.options.push(Obj);
                    });
                    vm.$refs.BarcodeReport.UpdateKeyValue();
                }
            });
        },
        GetBillingServiceCategory: async function () {
            var vm = this;
            DataServices.GetBillingServiceCategory().then((response) => {
                let SelectedBillingServiceList = [];
                var BillingServiceList = response.data;
                if (BillingServiceList != null) {
                    BillingServiceList.forEach(item => {
                        let obj = {
                            description: null,
                            displayValue: item.CATEGORY_NAME,
                            groupText: null,
                            groupValue: null,
                            metaData: null,
                            text: item.CATEGORY_NAME,
                            value: item.CATEGORY_ID
                        };
                        SelectedBillingServiceList.push(obj);
                    });
                    vm.$refs.BarcodeReport.updateProperty("ServiceCategory", "config.options", SelectedBillingServiceList);
                    vm.$refs.BarcodeReport.UpdateKeyValue();
                }
            });
        }
    }
};
</script>