<template lang="en">
<div>
    <loader :is-visible="isLoading"></loader>
    <section class="main-content">
        <div ref="hellp" id="divMaindealData">
            <div class="border p-3">
                <Form ref="JobPostForm">
                    <dynamic-form lang="en" ref="BarcodeReport" v-if="DataLoaded" :buttons="buttons" :schema="FormSchema" v-on:OnSubmit="onSubmit" :mandatorytext='MandatoryString'></dynamic-form>
                    <div class="row placeholder">
                        <div class="col-md-12 p-0">
                            <ReportViewer v-if="parameter.length > 0" :key="loadKey" :viewerId="'viewer_' + loadKey" :parameter="parameter" :reportPath="reportPath">
                            </ReportViewer>
                        </div>
                    </div>
                </Form>
            </div>
        </div>
    </section>
</div>
</template>
<script>
import '@boldreports/javascript-reporting-controls/Scripts/bold.report-designer.min';
import '@boldreports/javascript-reporting-controls/Scripts/bold.report-viewer.min';
import '@boldreports/javascript-reporting-controls/Scripts/data-visualization/ej.bulletgraph.min';
import '@boldreports/javascript-reporting-controls/Scripts/data-visualization/ej.chart.min';
import DataServices from "../../services/DataService";
import ReportViewer from '../../views/HrReport/ReportViewer.vue';
import moment from 'moment';
export default {
    components: {
        ReportViewer
    },
    data() {
        return {
            MandatoryString: 'Fields marked with an asterisk (*) are mandatory.',
            isLoading: false,
            loadKey: 0,
            reportPath: null,
            parameter: [],
            DataLoaded: 0,
            FormSchema: [{
                    layoutType: "triple",
                    Data: [{
                            astype: "SearchableSelectField",
                            label: this.$t("Contract"),
                            name: "Contract",
                            value: "",
                            placeholder: this.$t('Client'),
                            visibility: true,
                            isSearch: false,
                            config: {
                                options: [],
                                isMultiple: false,
                                minSearchLength: 0,
                                groupFields: [],
                                actionButtons: {
                                    clear: true
                                },
                                onChange: this.GetInvoiceGrouping
                            },
                            validationRules: {
                                required: true
                            }
                        },
                        {
                            astype: "SearchableSelectField",
                            label: this.$t("Invoice Grouping"),
                            name: "InvoiceGrouping",
                            value: "",
                            placeholder: this.$t('Select'),
                            visibility: true,
                            isSearch: false,
                            config: {
                                options: [],
                                isMultiple: false,
                                minSearchLength: 0,
                                groupFields: [],
                                actionButtons: {
                                    clear: true
                                }
                            },
                            validationRules: {
                                required: true
                            }
                        },
                        {
                            astype: "RadioField",
                            label: this.$t('ReportType'),
                            name: "ReportType",
                            value: "summary",
                            placeholder: "",
                            config: {
                                options: [{
                                    name: 'Invoice Backup Report',
                                    value: "Invoice"
                                }, {
                                    name: "Summary Report",
                                    value: "summary"
                                }],
                                onChange: this.LoadCompanies,
                                showAddIcon: false
                            },
                        }
                    ]
                },
                {
                    layoutType: "triple",
                    Data: [
                        {
                            astype: "DateRangeField",
                            label: this.$t('Process Date'),
                            name: "ProcessDateFrom",
                            value: "",
                            placeholder: "",
                            config: {
                                format: "MM/DD/YYYY",
                                maxDate: false,
                                onChange: this.setTimerDate,
                                datePickerConfig: {
                                    useCurrent: true,
                                    showClear: true,
                                    showClose: true,
                                    allowInputToggle: false,
                                    minDate: true,
                                    maxDate: true,
                                    widgetPositioning: {
                                        horizontal: 'right',
                                        vertical: 'bottom'
                                    }
                                },
                                secondDatePickerConfig: {
                                    useCurrent: false,
                                    showClear: true,
                                    showClose: true,
                                    allowInputToggle: false,
                                    minDate: true,
                                    maxDate: true,
                                    widgetPositioning: {
                                        horizontal: 'right',
                                        vertical: 'bottom'
                                    }
                                },
                            },
                            validationRules: {
                                "required": true
                            },
                        }
                    ]
                }
            ],
            buttons: [{
                    type: "submit",
                    class: "btn btn-success",
                    text: "<i class='fa fa-search pr-2'></i>Search",
                },
                {
                    type: "button",
                    class: "btn btn-danger",
                    text: "<i class='fa fa-close pr-2'></i>Clear all",
                    onClick: this.ClearAll
                }
            ]
        }
    },
    created: async function () {
        var vm = this;
        vm.userId = vm.GetUserInfo.ID;
        vm.companyId = vm.GetUserInfo.CompanyId;
        vm.UserType = vm.GetUserInfo.UserType;
        vm.DataLoaded = 1;
        await vm.GetClient();
    },
    methods: {
        setTimerDate: function (x, y, z) {
            var vm = this;
            if (y.name == "ProcessDateFrom") {
                vm.$refs.BarcodeReport.updateProperty("ProcessDateFrom", "config.secondDatePickerConfig.minDate", x);
                vm.$refs.BarcodeReport.UpdateKeyValue();
            }
        },
        formatDate(value) {
            if (!value) return null;
            const m = moment(value);
            return m.isValid() ? m.format('MM-DD-YYYY') : null;
        },
        async onSubmit(e) {
            var vm = this;
            vm.isLoading = true;
            vm.loadKey = Date.now();
            vm.reportPath = '';
            vm.parameter = [];
            vm.ProcessDateFrom = vm.$refs.BarcodeReport.getPropertyValue("ProcessDateFrom", "value");
            vm.ProcessDateTo = vm.$refs.BarcodeReport.getPropertyValue("ProcessDateFrom", "secondValue");
            let myObj = {
                reportName: "previewinvoicereport",
                ClientIds: e.Contract || '',
                DivisionId: e.InvoiceGrouping || '',
                IssuedFromDate: vm.formatDate(vm.ProcessDateFrom),
                IssuedToDate: vm.formatDate(vm.ProcessDateTo),
                ReportType: e.ReportType || ''
            };
            var postString = JSON.stringify(myObj);
            DataServices.ReportMain(postString).then(function (response) {
                vm.reportPath = response.data.reportpath;
                vm.parameter = response.data.parameters;
                vm.isLoading = false;
            }).catch(function (error) {
                console.error("Error loading report:", error);
                vm.isLoading = false;
            });
        },
        ClearAll: function () {
            var vm = this;
            (vm.FormSchema)[0].Data[0].value = '';
            (vm.FormSchema)[0].Data[1].value = '';
            (vm.FormSchema)[0].Data[1].config.options = [];
            (vm.FormSchema)[0].Data[2].value = 'summary';
            (vm.FormSchema)[1].Data[0].value = '';
            (vm.FormSchema)[1].Data[0].secondValue = '';
            vm.reportPath = '';
            vm.parameter = [];
            vm.loadKey = 0;
            vm.$refs.BarcodeReport.validateForm.reset();
        },
        GetClient: async function () {
            var vm = this;
            vm.isLoading = true;
            var params = 'pageNumber=&pageSize=&Reqfrom="CUSTOM"&search=null&userId=null';
            try {
                let response = await DataServices.GetClient(params);
                if (response.data && response.data.length > 0) {
                    let clientOptions = response.data.map(item => ({
                        text: item.CHILD_NAME,
                        displayValue: item.CHILD_NAME,
                        value: item.CHILD_USER_ID,
                        description: null,
                        groupText: null,
                        groupValue: null,
                        metaData: null
                    }));
                    vm.$refs.BarcodeReport.updateProperty("Contract", "config.options", clientOptions);
                    vm.$refs.BarcodeReport.UpdateKeyValue();
                } else {
                    vm.$refs.BarcodeReport.updateProperty("Contract", "config.options", []);
                    vm.$refs.BarcodeReport.UpdateKeyValue();
                }
            } catch (error) {
                console.error("Error fetching client list:", error);
                vm.$refs.BarcodeReport.updateProperty("Contract", "config.options", []);
                vm.$refs.BarcodeReport.UpdateKeyValue();
            } finally {
                vm.isLoading = false;
            }
        },
        GetInvoiceGrouping: async function (value, selectedValue) {
            var vm = this;
            // Reset Invoice Grouping dropdown
            vm.$refs.BarcodeReport.updateProperty("InvoiceGrouping", "config.options", []);
            vm.$refs.BarcodeReport.updateProperty("InvoiceGrouping", "value", '');
            vm.$refs.BarcodeReport.UpdateKeyValue();
            if (!selectedValue) return;
            // selectedValue IS the clientId
            var clientIds = selectedValue;
            var url = `ClientId=${clientIds}&UtilityIds=`;
            vm.isLoading = true;
            try {
                let response = await DataServices.GetInvoiceGrouping(url);
                if (response.data && response.data.length > 0) {
                    let groupingOptions = response.data.map(item => ({
                        text: item.NOTE,
                        displayValue: item.NOTE,
                        value: item.ID,
                        description: null,
                        groupText: null,
                        groupValue: null,
                        metaData: null
                    }));
                    vm.$refs.BarcodeReport.updateProperty("InvoiceGrouping", "config.options", groupingOptions);
                    vm.$refs.BarcodeReport.UpdateKeyValue();
                }
            } catch (error) {
                console.error("Error loading invoice grouping list:", error);
                vm.$refs.BarcodeReport.updateProperty("InvoiceGrouping", "config.options", []);
                vm.$refs.BarcodeReport.UpdateKeyValue();
            } finally {
                vm.isLoading = false;
            }
        },
        LoadCompanies: function () {
            // Implementation for LoadCompanies if needed, otherwise leave as is
        }
    }
}
</script>